// frontend/src/services/webSerialService.js
class WebSerialService {
    constructor() {
        this.port = null;
        this.reader = null;
        this.writer = null;
        this.isConnected = false;
        this.eventListeners = {};
        this.readLoopActive = false;
        this.buffer = '';
    }

    async connect() {
        if (!navigator.serial) {
            throw new Error('Web Serial is not supported. Please use Chrome or Edge browser.');
        }

        if (this.isConnected && this.port) {
            console.log('Already connected to a serial port');
            return { success: true };
        }

        try {
            console.log('🔍 Requesting serial port...');
            
            this.port = await navigator.serial.requestPort({
                filters: [
                    { usbVendorId: 0x10c4 }, // Silicon Labs CP210x
                    { usbVendorId: 0x1a86 }, // CH340
                    { usbVendorId: 0x0403 }  // FTDI
                ]
            });
            
            console.log('🔗 Connecting to serial port...');
            await this.port.open({ baudRate: 115200 });
            
            this.isConnected = true;
            console.log('✅ Serial port connected!');
            
            this.startReading();
            
            // Test connection
            await this.sendCommand('PING');
            
            return { success: true };
        } catch (error) {
            console.error('❌ Connection error:', error);
            this.isConnected = false;
            this.port = null;
            return { success: false, error: error.message };
        }
    }

    async startReading() {
        if (this.readLoopActive) return;
        this.readLoopActive = true;
        
        while (this.port && this.port.readable) {
            try {
                this.reader = this.port.readable.getReader();
                
                while (true) {
                    const { value, done } = await this.reader.read();
                    if (done) break;
                    
                    // Decode the received data
                    const text = new TextDecoder().decode(value);
                    console.log('📨 Raw received:', text);
                    this.buffer += text;
                    
                    // Process complete lines
                    let lines = this.buffer.split('\n');
                    this.buffer = lines.pop() || '';
                    
                    for (const line of lines) {
                        if (line.trim()) {
                            const trimmedLine = line.trim();
                            console.log('📨 Processed line:', trimmedLine);
                            
                            // Remove any "Received: " prefix from echo
                            let cleanLine = trimmedLine;
                            if (cleanLine.startsWith('Received:')) {
                                cleanLine = cleanLine.substring(8).trim();
                            }
                            
                            this.emit('data', cleanLine);
                        }
                    }
                }
            } catch (error) {
                console.error('Read error:', error);
                break;
            } finally {
                if (this.reader) {
                    this.reader.releaseLock();
                }
            }
        }
        
        this.readLoopActive = false;
    }

    async sendCommand(command) {
        if (!this.isConnected || !this.port || !this.port.writable) {
            throw new Error('Not connected to device');
        }
        
        try {
            this.writer = this.port.writable.getWriter();
            const data = new TextEncoder().encode(command + '\n');
            await this.writer.write(data);
            this.writer.releaseLock();
            console.log('📤 Sent:', command);
        } catch (error) {
            console.error('Send error:', error);
            throw error;
        }
    }

    async scanFingerprint() {
        return new Promise((resolve, reject) => {
            console.log('Starting fingerprint scan...');
            
            let resolved = false;
            let receivedMessages = [];
            
            const timeout = setTimeout(() => {
                if (!resolved) {
                    console.log('Scan timeout. Received messages:', receivedMessages);
                    reject(new Error('Scan timeout - Please place your finger on the sensor'));
                    cleanup();
                }
            }, 15000);
            
            const handler = (response) => {
                console.log('Scan response handler received:', response);
                receivedMessages.push(response);
                
                if (response.startsWith('SCAN_SUCCESS')) {
                    if (!resolved) {
                        resolved = true;
                        clearTimeout(timeout);
                        const match = response.match(/ID=(\d+),CONFIDENCE=(\d+)/);
                        resolve({
                            success: true,
                            userId: match ? parseInt(match[1]) : null,
                            confidence: match ? parseInt(match[2]) : 0
                        });
                        cleanup();
                    }
                } else if (response.startsWith('SCAN_FAIL')) {
                    if (!resolved) {
                        resolved = true;
                        clearTimeout(timeout);
                        reject(new Error(response));
                        cleanup();
                    }
                } else if (response === 'SCAN_START') {
                    console.log('✅ Scan started, waiting for finger...');
                    // Don't resolve, just continue listening
                }
            };
            
            const cleanup = () => {
                this.off('data', handler);
            };
            
            this.on('data', handler);
            this.sendCommand('SCAN').catch((err) => {
                cleanup();
                reject(err);
            });
        });
    }

    async enrollFingerprint() {
        return new Promise((resolve, reject) => {
            const timeout = setTimeout(() => {
                reject(new Error('Enrollment timeout'));
            }, 45000);
            
            let resolved = false;
            
            const dataHandler = (response) => {
                if (response.startsWith('ENROLL_SUCCESS')) {
                    if (!resolved) {
                        resolved = true;
                        clearTimeout(timeout);
                        const match = response.match(/ID=(\d+)/);
                        resolve({
                            success: true,
                            userId: match ? parseInt(match[1]) : null
                        });
                        this.off('data', dataHandler);
                    }
                } else if (response.startsWith('ENROLL_FAIL')) {
                    if (!resolved) {
                        resolved = true;
                        clearTimeout(timeout);
                        reject(new Error(response));
                        this.off('data', dataHandler);
                    }
                } else if (response.startsWith('ENROLL_START') || response.startsWith('ENROLL_STEP')) {
                    console.log('Enrollment step:', response);
                    this.emit('status', response);
                }
            };
            
            this.on('data', dataHandler);
            this.sendCommand('ENROLL').catch(reject);
        });
    }

    async getStatus() {
        return new Promise((resolve, reject) => {
            const timeout = setTimeout(() => {
                reject(new Error('Status timeout'));
            }, 5000);
            
            const handler = (response) => {
                if (response === 'STATUS:OK') {
                    clearTimeout(timeout);
                    resolve({ success: true });
                    this.off('data', handler);
                } else if (response === 'STATUS:ERROR') {
                    clearTimeout(timeout);
                    resolve({ success: false });
                    this.off('data', handler);
                }
            };
            
            this.on('data', handler);
            this.sendCommand('STATUS').catch(reject);
        });
    }

    on(event, callback) {
        if (!this.eventListeners[event]) {
            this.eventListeners[event] = [];
        }
        this.eventListeners[event].push(callback);
    }

    once(event, callback) {
        const wrapper = (...args) => {
            callback(...args);
            this.off(event, wrapper);
        };
        this.on(event, wrapper);
    }

    off(event, callback) {
        if (this.eventListeners[event]) {
            this.eventListeners[event] = this.eventListeners[event].filter(cb => cb !== callback);
        }
    }

    emit(event, data) {
        if (this.eventListeners[event]) {
            this.eventListeners[event].forEach(callback => callback(data));
        }
    }

    async disconnect() {
        this.isConnected = false;
        
        if (this.reader) {
            await this.reader.cancel();
            this.reader.releaseLock();
        }
        
        if (this.writer) {
            this.writer.releaseLock();
        }
        
        if (this.port) {
            await this.port.close();
            this.port = null;
        }
        
        console.log('Disconnected from serial device');
    }
}

export default WebSerialService;
